define('tiny_imageia/configuration', ['editor_tiny/utils'], function(TinyUtils) {
  const buttonName = 'tiny_imageia_imageia';
  const menuItemName = 'tiny_imageia_imageia';
  const configure = (instanceConfig) => {
    let toolbar = instanceConfig.toolbar;
    toolbar = TinyUtils.addToolbarButtons(toolbar, 'content', [buttonName]);
    let menu = instanceConfig.menu;
    menu = TinyUtils.addMenubarItem(menu, 'insert', [menuItemName].join(' '));
    return {toolbar, menu};
  };
  return {configure};
});
